package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testWithHeader() throws SQLException {
        // Create a mock ResultSet
        ResultSet resultSet = Mockito.mock(ResultSet.class);
        ResultSetMetaData metaData = Mockito.mock(ResultSetMetaData.class);

        // Define the behavior of the mock objects
        Mockito.when(resultSet.getMetaData()).thenReturn(metaData);

        // Create an instance of CSVFormat
        CSVFormat csvFormat = new CSVFormat(COMMA, DOUBLE_QUOTE_CHAR, null, null, null, false, true, CRLF,
                null, null, null, false, false, false, false, false);

        // Call the focal method
        CSVFormat result = csvFormat.withHeader(resultSet);

        // Validate the result
        assertEquals(csvFormat, result); // You may need to adjust the assertion based on the actual logic in withHeader()
    }
}
